async function seed() {
  const db = await getDb();
  
  console.log('Iniciando importación FHIS 2016...');
  
  // 1. Insertar insumos del catálogo FHIS
  let insumosInsertados = 0;
  const insumoIdMap = {};
  
  for (const [codigo, ins] of Object.entries(insumosCatalogo)) {
    try {
      const exists = db.exec('SELECT id_insumo FROM insumos WHERE codigo = ?', [codigo]);
      if (exists.length && exists[0].values.length) {
        insumoIdMap[codigo] = exists[0].values[0][0];
        continue;
      }
      db.run(
        'INSERT INTO insumos (codigo, descripcion, unidad, id_categoria, precio_unitario, fecha_actualizacion, activo) VALUES (?,?,?,?,0,date(\'now\'),1)',
        [codigo, ins.descripcion, ins.unidad, ins.cat_id]
      );
      const r = db.exec('SELECT last_insert_rowid()');
      insumoIdMap[codigo] = r[0].values[0][0];
      insumosInsertados++;
    } catch(e) {}
  }
  console.log(`Insumos insertados: ${insumosInsertados}`);
  
  // 2. Insertar actividades FHIS
  let actInsertadas = 0;
  const actIdMap = {};
  
  for (const act of actividades) {
    try {
      const exists = db.exec('SELECT id_actividad FROM actividades WHERE codigo = ?', [act.codigo]);
      if (exists.length && exists[0].values.length) {
        actIdMap[act.codigo] = exists[0].values[0][0];
        continue;
      }
      db.run(
        'INSERT INTO actividades (codigo, descripcion, unidad, costo_total) VALUES (?,?,?,0)',
        [act.codigo, act.descripcion, act.unidad]
      );
      const r = db.exec('SELECT last_insert_rowid()');
      actIdMap[act.codigo] = r[0].values[0][0];
      actInsertadas++;
    } catch(e) {}
  }
  console.log(`Actividades insertadas: ${actInsertadas}`);
  
  // 3. Insertar detalles actividad_insumos
  let detInsertados = 0;
  for (const det of detalles) {
    const actId = actIdMap[det.act_codigo];
    const insId = insumoIdMap[det.cod_insumo];
    if (!actId || !insId) continue;
    try {
      db.run(
        'INSERT INTO actividad_insumos (id_actividad, id_insumo, cantidad, rendimiento, desperdicio, costo_parcial) VALUES (?,?,?,?,?,0)',
        [actId, insId, det.rendimiento, 1, det.desperdicio]
      );
      detInsertados++;
    } catch(e) {}
  }
  console.log(`Detalles insertados: ${detInsertados}`);
  
  saveDb();
  console.log('\n✅ Importación FHIS 2016 completada.');
  console.log(`   ${actInsertadas} actividades | ${insumosInsertados} insumos | ${detInsertados} detalles`);
  process.exit(0);
}

seed().catch(e => { console.error(e); process.exit(1); });
